const StorageKeys = { theme: 'app-theme', accent: 'app-accent-color' };
const Defaults = { theme: 'System', accent: '#0d6efd' };

// Resolve effective theme (light/dark) from a preference that may be "System"
function resolveEffective(pref) {
    if (pref === 'System') {
        return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'Dark' : 'Light';
    }
    return pref;
}

function applyToDom(theme, accent) {
    const effective = resolveEffective(theme);
    document.documentElement.setAttribute('data-bs-theme', effective.toLowerCase());
    document.documentElement.style.setProperty('--app-accent-color', accent);
}

// --- Public API exposed to .NET via IJSRuntime ---

export function getTheme() {
    return localStorage.getItem(StorageKeys.theme) ?? Defaults.theme;
}

export function getAccentColor() {
    return localStorage.getItem(StorageKeys.accent) ?? Defaults.accent;
}

export function setTheme(theme) {
    localStorage.setItem(StorageKeys.theme, theme);
    applyToDom(theme, getAccentColor());
    window.dispatchEvent(new CustomEvent('app-theme-changed', { detail: { theme, accent: getAccentColor() } }));
}

export function setAccentColor(accent) {
    localStorage.setItem(StorageKeys.accent, accent);
    applyToDom(getTheme(), accent);
    window.dispatchEvent(new CustomEvent('app-theme-changed', { detail: { theme: getTheme(), accent } }));
}

export function initialize() {
    applyToDom(getTheme(), getAccentColor());
}

// Register a .NET object to receive change notifications.
// Returns a listener ID so we can remove it on dispose.
let listenerCounter = 0;
const listeners = new Map();

export function addChangeListener(dotNetRef) {
    const id = ++listenerCounter;
    const handler = (e) => {
        dotNetRef.invokeMethodAsync('OnThemeChangedFromJs', e.detail.theme, e.detail.accent);
    };
    window.addEventListener('app-theme-changed', handler);
    listeners.set(id, handler);
    return id;
}

export function removeChangeListener(id) {
    const handler = listeners.get(id);
    if (handler) {
        window.removeEventListener('app-theme-changed', handler);
        listeners.delete(id);
    }
}

// React to OS-level color scheme changes when preference is "System"
window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
    const pref = getTheme();
    if (pref === 'System') {
        applyToDom(pref, getAccentColor());
        window.dispatchEvent(new CustomEvent('app-theme-changed', { detail: { theme: pref, accent: getAccentColor() } }));
    }
});

using Microsoft.JSInterop;

namespace sv_ea48748b57c245868407c867f5011cdb.Services;

public enum ThemeMode { Light, Dark, System }

public sealed class ThemeInterop : IAsyncDisposable
{
    private readonly Lazy<Task<IJSObjectReference>> _moduleTask;

    public ThemeInterop(IJSRuntime jsRuntime)
    {
        _moduleTask = new(() => jsRuntime.InvokeAsync<IJSObjectReference>(
            "import", "./js/theme.js").AsTask());
    }

    public async Task InitializeAsync()
    {
        var module = await _moduleTask.Value;
        await module.InvokeVoidAsync("initialize");
    }

    public async Task<ThemeMode> GetThemeAsync()
    {
        var module = await _moduleTask.Value;
        var value = await module.InvokeAsync<string>("getTheme");
        return Enum.Parse<ThemeMode>(value);
    }

    public async Task<string> GetAccentColorAsync()
    {
        var module = await _moduleTask.Value;
        return await module.InvokeAsync<string>("getAccentColor");
    }

    public async Task SetThemeAsync(ThemeMode theme)
    {
        var module = await _moduleTask.Value;
        await module.InvokeVoidAsync("setTheme", theme.ToString());
    }

    public async Task SetAccentColorAsync(string color)
    {
        var module = await _moduleTask.Value;
        await module.InvokeVoidAsync("setAccentColor", color);
    }

    public async Task<int> AddChangeListenerAsync(DotNetObjectReference<IThemeChangeHandler> dotNetRef)
    {
        var module = await _moduleTask.Value;
        return await module.InvokeAsync<int>("addChangeListener", dotNetRef);
    }

    public async Task RemoveChangeListenerAsync(int listenerId)
    {
        var module = await _moduleTask.Value;
        await module.InvokeVoidAsync("removeChangeListener", listenerId);
    }

    public async ValueTask DisposeAsync()
    {
        if (_moduleTask.IsValueCreated)
