+// Returns a listener ID so we can remove it on dispose.
+let listenerCounter = 0;
+const listeners = new Map();
+
+export function addChangeListener(dotNetRef) {
+    const id = ++listenerCounter;
+    const handler = (e) => {
+        dotNetRef.invokeMethodAsync('OnThemeChangedFromJs', e.detail.theme, e.detail.accent);
+    };
+    window.addEventListener('app-theme-changed', handler);
+    listeners.set(id, handler);
+    return id;
+}
+
+export function removeChangeListener(id) {
+    const handler = listeners.get(id);
+    if (handler) {
+        window.removeEventListener('app-theme-changed', handler);
+        listeners.delete(id);
+    }
+}
+
+// React to OS-level color scheme changes when preference is "System"
