+    const pref = getTheme();
+    if (pref === 'System') {
+        applyToDom(pref, getAccentColor());
+        window.dispatchEvent(new CustomEvent('app-theme-changed', { detail: { theme: pref, accent: getAccentColor() } }));
+    }
+});
