@rendermode InteractiveServer
@implements IThemeChangeHandler
@implements IAsyncDisposable
@inject ThemeInterop ThemeInterop

<span class="theme-indicator" title="Current theme: @CurrentTheme">
    @(CurrentTheme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark  => "🌙",
        _               => "💻"
    })
    @CurrentTheme
    @if (!string.IsNullOrEmpty(AccentColor))
    {
        <span class="accent-swatch" style="background-color: @AccentColor;" title="Accent: @AccentColor"></span>
    }
</span>

@code {
    private DotNetObjectReference<IThemeChangeHandler>? _selfRef;
    private int _listenerId;

    public ThemeMode CurrentTheme { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        await ThemeInterop.InitializeAsync();
        CurrentTheme = await ThemeInterop.GetThemeAsync();
        AccentColor = await ThemeInterop.GetAccentColorAsync();

        _selfRef = DotNetObjectReference.Create<IThemeChangeHandler>(this);
        _listenerId = await ThemeInterop.AddChangeListenerAsync(_selfRef);

        StateHasChanged();
    }

    [JSInvokable]
    public Task OnThemeChangedFromJs(string theme, string accent)
    {
        CurrentTheme = Enum.Parse<ThemeMode>(theme);
        AccentColor = accent;
        InvokeAsync(StateHasChanged);
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        if (_listenerId > 0)
        {
            await ThemeInterop.RemoveChangeListenerAsync(_listenerId);
        }
        _selfRef?.Dispose();
    }
}

