+@page "/settings"
+@rendermode InteractiveServer
+@implements IThemeChangeHandler
+@implements IAsyncDisposable
+@inject ThemeInterop ThemeInterop
+
+<PageTitle>Settings</PageTitle>
+
+<h1>User Preferences</h1>
+
+<div class="card mt-3" style="max-width: 480px;">
+    <div class="card-body">
+        <h5 class="card-title">Theme</h5>
+        <div class="btn-group mb-3" role="group">
+            @foreach (var mode in Enum.GetValues<ThemeMode>())
+            {
+                var isActive = mode == _theme;
+                <button type="button"
+                        class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
+                        @onclick="() => SetTheme(mode)">
+                    @mode
+                </button>
+            }
+        </div>
+
+        <h5 class="card-title">Accent Color</h5>
+        <div class="d-flex align-items-center gap-3 mb-3">
+            <input type="color" class="form-control form-control-color"
+                   value="@_accent" @onchange="OnAccentChanged" />
+            <span>@_accent</span>
+        </div>
+
+        <div class="alert alert-info mb-0">
+            Current theme: <strong>@_theme</strong> &mdash; Accent: 
+            <span style="color: @_accent; font-weight: bold;">@_accent</span>
+        </div>
+    </div>
+</div>
+
+@code {
+    private ThemeMode _theme = ThemeMode.System;
+    private string _accent = "#0d6efd";
+    private DotNetObjectReference<IThemeChangeHandler>? _selfRef;
+    private int _listenerId;
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (!firstRender) return;
+
+        _theme = await ThemeInterop.GetThemeAsync();
+        _accent = await ThemeInterop.GetAccentColorAsync();
+
+        _selfRef = DotNetObjectReference.Create<IThemeChangeHandler>(this);
+        _listenerId = await ThemeInterop.AddChangeListenerAsync(_selfRef);
+
+        StateHasChanged();
+    }
+
+    private async Task SetTheme(ThemeMode mode)
+    {
+        _theme = mode;
+        await ThemeInterop.SetThemeAsync(mode);
+    }
+
+    private async Task OnAccentChanged(ChangeEventArgs e)
+    {
+        _accent = e.Value?.ToString() ?? _accent;
+        await ThemeInterop.SetAccentColorAsync(_accent);
+    }
+
+    [JSInvokable]
+    public Task OnThemeChangedFromJs(string theme, string accent)
+    {
+        _theme = Enum.Parse<ThemeMode>(theme);
+        _accent = accent;
+        InvokeAsync(StateHasChanged);
+        return Task.CompletedTask;
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (_listenerId > 0)
+        {
+            await ThemeInterop.RemoveChangeListenerAsync(_listenerId);
+        }
+        _selfRef?.Dispose();
+    }
+}
